# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests
from urllib.parse import urlparse

ALLOWED_SCHEMES = {"http", "https"}
MAX_FETCH_BYTES = 64 * 1024
TIMEOUT_SECONDS = 2.0


def _response(status, status_description, body, content_type="application/json"):
    return {
        "status": str(status),
        "statusDescription": status_description,
        "headers": {
            "content-type": [{"key": "Content-Type", "value": content_type}],
            "cache-control": [{"key": "Cache-Control", "value": "no-store"}],
        },
        "body": body,
    }


def _get_header_value(headers, name):
    key = name.lower()
    if key not in headers or not headers[key]:
        return None
    return headers[key][0].get("value")


def _set_header(headers, name, value):
    headers[name.lower()] = [{"key": name, "value": value}]


def _safe_fetch(url):
    parsed = urlparse(url)
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise ValueError("Unsupported URL scheme")
    if not parsed.netloc:
        raise ValueError("Invalid URL")

    resp = requests.get(
        url,
        timeout=TIMEOUT_SECONDS,
        allow_redirects=False,
        stream=True,
        headers={"User-Agent": "LambdaEdge-Enrichment/1.0"},
    )
    resp.raise_for_status()

    chunks = []
    total = 0
    for chunk in resp.iter_content(chunk_size=8192):
        if not chunk:
            continue
        total += len(chunk)
        if total > MAX_FETCH_BYTES:
            raise ValueError("Fetched content too large")
        chunks.append(chunk)

    content = b"".join(chunks)
    content_type = resp.headers.get("Content-Type", "application/octet-stream")
    return content, content_type


def lambda_handler(event, context):
    record = event["Records"][0]["cf"]
    request = record["request"]
    headers = request.get("headers", {})

    enrich_url = _get_header_value(headers, "X-Enrich-URL")
    if enrich_url:
        try:
            content, content_type = _safe_fetch(enrich_url)
            try:
                fetched = json.loads(content.decode("utf-8"))
            except Exception:
                fetched = {
                    "content": content.decode("utf-8", errors="replace"),
                    "contentType": content_type,
                }

            _set_header(headers, "X-Enrich-Data", json.dumps(fetched, separators=(",", ":")))
            _set_header(headers, "X-Enrich-Source", enrich_url)
        except Exception as exc:
            return _response(
                400,
                "Bad Request",
                json.dumps(
                    {
                        "message": "Failed to fetch enrichment data",
                        "error": str(exc),
                    }
                ),
            )

    request["headers"] = headers
    return request